// Minimal highlight.js stub - basic syntax highlighting
var hljs = (function() {
    var KEYWORDS = {
        rust: /\b(fn|let|mut|pub|use|mod|struct|enum|impl|trait|async|await|match|if|else|for|while|loop|return|self|Self|super|crate|where|type|const|static|ref|move|dyn|unsafe|extern|as|in|break|continue|true|false)\b/g,
        javascript: /\b(function|const|let|var|if|else|for|while|return|class|new|this|async|await|import|export|from|default|try|catch|throw|typeof|instanceof|true|false|null|undefined)\b/g,
        python: /\b(def|class|if|elif|else|for|while|return|import|from|as|try|except|finally|raise|with|yield|lambda|pass|True|False|None|and|or|not|in|is)\b/g,
        powershell: /\b(Get|Set|New|Remove|Start|Stop|Write|Read|Select|Where|ForEach|Invoke|param|function|if|else|return)\b/gi,
        bash: /\b(if|then|else|elif|fi|for|while|do|done|case|esac|function|return|echo|exit|export|source)\b/g,
    };

    function highlight(code, opts) {
        var lang = (opts && opts.language) || '';
        var html = escapeHtml(code);
        var kw = KEYWORDS[lang];
        if (kw) {
            html = html.replace(kw, '<span style="color:#ff7b72">$1</span>');
        }
        // Strings
        html = html.replace(/(["'])((?:(?!\1).)*?)\1/g, '<span style="color:#a5d6ff">$1$2$1</span>');
        // Comments
        html = html.replace(/(\/\/.*$)/gm, '<span style="color:#6e7681">$1</span>');
        html = html.replace(/(#.*$)/gm, '<span style="color:#6e7681">$1</span>');
        // Numbers
        html = html.replace(/\b(\d+\.?\d*)\b/g, '<span style="color:#79c0ff">$1</span>');
        return { value: html };
    }

    function escapeHtml(s) {
        return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    }

    return {
        highlight: highlight,
        getLanguage: function(lang) { return !!KEYWORDS[lang]; }
    };
})();
